const now = new Date();

// post_log.jsonをデコード
let log = { posts: [] };
try {
  const raw = $input.first().json.content.replace(/\n/g, '');
  log = JSON.parse(Buffer.from(raw, 'base64').toString('utf-8'));
} catch(e) {
  return [{ json: { _skip: true, reason: 'parse_error' } }];
}

if (!log.posts || log.posts.length === 0) {
  return [{ json: { _skip: true, reason: 'no_posts' } }];
}

// 過去7日以内の投稿でmetricsが必要なものを抽出
const targets = log.posts.filter(post => {
  if (!post.threads_id) return false;
  const postedAt = new Date(post.posted_at);
  const hoursSince = (now - postedAt) / (1000 * 60 * 60);
  return hoursSince >= 1 && hoursSince <= 168; // 1時間〜7日以内
}).map(post => {
  const postedAt = new Date(post.posted_at);
  const hoursSince = Math.floor((now - postedAt) / (1000 * 60 * 60));
  let timing = 'ongoing';
  if (hoursSince >= 168) timing = '7day';
  else if (hoursSince >= 72) timing = '72h';
  else if (hoursSince >= 24) timing = '24h';
  else timing = '1h';
  return { ...post, collection_timing: timing };
});

if (targets.length === 0) {
  return [{ json: { _skip: true, reason: 'no_posts_in_range' } }];
}

return targets.map(p => ({ json: p }));

// 全投稿のメトリクス結果を集計する
const results = $input.all();
const records = results.map(item => {
  const metrics = {};
  const dataArr = item.json.data || [];
  dataArr.forEach(m => {
    metrics[m.name] = m.values ? m.values[0]?.value : m.total_value?.value || 0;
  });
  return {
    post_no: item.json._post_no || '',
    threads_id: item.json._threads_id || '',
    collection_timing: item.json._timing || '',
    collected_at: new Date().toISOString(),
    views: metrics.views || 0,
    likes: metrics.likes || 0,
    replies: metrics.replies || 0,
    reposts: metrics.reposts || 0,
    quotes: metrics.quotes || 0
  };
});

return [{ json: { records } }];

const newRecords = $('メトリクス集計').first().json.records || [];
const metricsFile = $('daily_metrics取得').first().json;

// 既存ファイルをデコード
let metrics = { collected_by: 'データ回収部門', records: [], account: {} };
try {
  const raw = metricsFile.content.replace(/\n/g, '');
  metrics = JSON.parse(Buffer.from(raw, 'base64').toString('utf-8'));
} catch(e) {}

// 今日の日付
const today = new Date().toISOString().split('T')[0];

// 新しいレコードを追加（重複チェック：同じpost_no + timing は上書き）
newRecords.forEach(rec => {
  const key = `${rec.post_no}_${rec.collection_timing}`;
  const idx = metrics.records.findIndex(
    r => r.post_no === rec.post_no && r.collection_timing === rec.collection_timing
  );
  if (idx >= 0) {
    metrics.records[idx] = rec; // 上書き
  } else {
    metrics.records.push(rec);
  }
});

metrics.collected_at = new Date().toISOString();
metrics.status = 'completed';

const encoded = Buffer.from(JSON.stringify(metrics, null, 2)).toString('base64');

return [{
  json: {
    message: `データ収集: ${today} (${newRecords.length}件)`,
    content: encoded,
    sha: metricsFile.sha
  }
}];
